import type { Misconception, MisconceptionState } from "@/lib/types";

type SamStatePanelProps = {
  misconceptions: Misconception[];
  states: Record<string, MisconceptionState>;
};

const LABEL_BY_STATE: Record<MisconceptionState, string> = {
  entrenched: "Entrenched",
  aware: "Aware",
  considering: "Considering",
  updating: "Updating",
  settled: "Settled",
};

const DOT_BY_STATE: Record<MisconceptionState, string> = {
  entrenched: "bg-slate-400",
  aware: "bg-violet-400",
  considering: "bg-fuchsia-400",
  updating: "bg-cyan-500",
  settled: "bg-emerald-500",
};

export function SamStatePanel({ misconceptions, states }: SamStatePanelProps) {
  return (
    <div className="rounded-2xl border border-slate-200 bg-white p-4 shadow-md">
      <p className="text-xs font-semibold uppercase tracking-wide text-slate-600">Sam&apos;s beliefs</p>
      <div className="mt-3 space-y-3">
        {misconceptions.map((misconception) => {
          const state = states[misconception.id] ?? "entrenched";
          return (
            <div key={misconception.id} className="flex items-start gap-3">
              <span className={`mt-1 inline-block h-2.5 w-2.5 rounded-full ${DOT_BY_STATE[state]}`} />
              <div className="min-w-0">
                <p className="text-xs font-semibold uppercase tracking-wide text-slate-500">
                  {LABEL_BY_STATE[state]}
                </p>
                <p className="text-sm leading-snug text-slate-700">{misconception.belief}</p>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
